from itertools import permutations

class Solution:
    def reconstructQueue(self, people):
        n = len(people)
        for perm in permutations(people):
            ok = True
            for i in range(n):
                h, k = perm[i]
                count = sum(1 for j in range(i) if perm[j][0] >= h)
                if count != k:
                    ok = False
                    break
            if ok:
                return [list(p) for p in perm]
        return []

