var reconstructQueue = function(people) {
    const ordered = people.slice().sort((a, b) => (b[0] - a[0]) || (a[1] - b[1]));
    const result = [];
    for (const p of ordered) {
        result.splice(p[1], 0, p);
    }
    return result;
};
